public String lexSmallestString(String s, int k) {
    String res = s;
    for (int i = 0; i < k; i++) {
        String tmp = s.substring(i) + s.substring(0, i);
        if (tmp.compareTo(res) < 0) {
            res = tmp;
        }
    }
    return res;
}
